using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes a message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Adds two numbers together.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b)
    {
        return a + b;
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            Features = new { Logging = true, Metrics = true }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "info://server/status",
        Name = "Server Status",
        MimeType = "application/json"),
     Description("Returns current server status and uptime information.")]
    public static string GetServerStatus()
    {
        var status = new
        {
            Status = "healthy",
            StartedAt = Program.StartedAt,
            Uptime = (DateTime.UtcNow - Program.StartedAt).ToString()
        };

        return JsonSerializer.Serialize(status, new JsonSerializerOptions { WriteIndented = true });
    }
}

